def search_and_aggregate_scores(
    index_path: str,
    query: str,
    aggregate_by_field: str,
    top_k: int = 10
) -> Dict[str, Dict[str, float]]:
    """Search in an index and aggregate scores by a metadata field."""
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")
    except Exception as e:
        # Re-raise other exceptions as-is
        raise

    results = searcher.search(query, top_k=top_k)

    aggregated_data = defaultdict(lambda: {
        'count': 0,
        'sum_scores': 0.0,
        'max_score': float('-inf'),
        'min_score': float('inf')
    })

    for result in results:
        field_value = result.metadata.get(aggregate_by_field)
        if field_value is None:
            continue
        score = result.score
        data = aggregated_data[field_value]
        data['count'] += 1
        data['sum_scores'] += score
        if score > data['max_score']:
            data['max_score'] = score
        if score < data['min_score']:
            data['min_score'] = score

    result_dict = {}
    for field_value, stats in aggregated_data.items():
        stats['avg_score'] = stats['sum_scores'] / stats['count']
        result_dict[field_value] = stats

    return result_dict

