from collections import Counter, defaultdict

def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index."""
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    searcher = LeannSearcher(index_path)
    passage_manager = searcher.passage_manager
    passages = passage_manager.get_all_passages()

    total_passages = len(passages)

    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    for passage in passages:
        metadata = passage.metadata
        for field_name in metadata:
            metadata_fields.add(field_name)
            field_value_counts[field_name].update([metadata[field_name]])

    field_value_counts_dict = {
        field: dict(counter) 
        for field, counter in field_value_counts.items()
    }

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(metadata_fields),
        "field_value_counts": field_value_counts_dict
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields."""
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    searcher = LeannSearcher(index_path)
    passage_manager = searcher.passage_manager
    passages = passage_manager.get_all_passages()

    total_passages = len(passages)

    if total_passages == 0:
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": required_fields
        }

    all_fields = set()
    for passage in passages:
        all_fields.update(passage.metadata.keys())

    missing_fields = [field for field in required_fields if field not in all_fields]

    passages_with_all_fields = 0
    field_counts = {field: 0 for field in required_fields}

    for passage in passages:
        has_all_fields = True
        for field in required_fields:
            if field not in passage.metadata:
                has_all_fields = False
                break
        if has_all_fields:
            passages_with_all_fields += 1
        for field in required_fields:
            if field in passage.metadata:
                field_counts[field] += 1

    coverage_percentage = (passages_with_all_fields / total_passages) * 100
    field_coverage = {
        field: (field_counts[field] / total_passages) * 100 
        for field in required_fields
    }

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": {field: round(perc, 2) for field, perc in field_coverage.items()},
        "missing_fields": missing_fields
    }

from typing import List, Dict, Any
from leann.api import LeannBuilder
from pathlib import Path

def build_index_with_metadata_template(
    documents: List[Dict[str, Any]],
    index_path: str,
    metadata_template: Dict[str, Any] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index and apply a metadata template to all documents."""
    if not documents:
        raise ValueError("documents list cannot be empty")

    processed_docs = []
    for doc in documents:
        if metadata_template is None:
            merged_metadata = doc.get('metadata', {})
        else:
            if 'metadata' in doc:
                merged_metadata = {**metadata_template, **doc['metadata']}
            else:
                merged_metadata = metadata_template.copy()
        processed_docs.append({
            'text': doc['text'],
            'metadata': merged_metadata
        })

    builder = LeannBuilder(backend_name=backend_name)
    for doc in processed_docs:
        builder.add_text(doc['text'], metadata=doc['metadata'])

    # Ensure directory exists
    path = Path(index_path)
    path.parent.mkdir(parents=True, exist_ok=True)

    builder.build_index(str(path))
    return str(path)

